/* ─────────────────────────────────────────────────────────
    AMBIENT FLOATING ORBS — Premium Background Layer
───────────────────────────────────────────────────────── */
@keyframes orb-float-1 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  25%       { transform: translate(60px, -40px) scale(1.08); }
  50%       { transform: translate(-30px, 30px) scale(0.95); }
  75%       { transform: translate(40px, 60px) scale(1.04); }
}
@keyframes orb-float-2 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33%       { transform: translate(-80px, 50px) scale(1.12); }
  66%       { transform: translate(50px, -30px) scale(0.92); }
}
@keyframes orb-float-3 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  20%       { transform: translate(40px, 80px) scale(1.05); }
  60%       { transform: translate(-60px, -40px) scale(1.1); }
  80%       { transform: translate(30px, -20px) scale(0.98); }
}
@keyframes orb-pulse {
  0%, 100% { opacity: 0.4; filter: blur(60px); }
  50%       { opacity: 0.65; filter: blur(80px); }
}

/* Grid background animation */
@keyframes grid-drift {
  0%   { transform: perspective(500px) rotateX(30deg) translateY(0); }
  100% { transform: perspective(500px) rotateX(30deg) translateY(40px); }
}

/* Aurora / Nebula effect */
@keyframes aurora-shift {
  0%   { transform: translate(0, 0) rotate(0deg) scale(1); filter: blur(80px); }
  33%  { transform: translate(100px, -60px) rotate(5deg) scale(1.1); filter: blur(100px); }
  66%  { transform: translate(-60px, 80px) rotate(-3deg) scale(0.95); filter: blur(60px); }
  100% { transform: translate(0, 0) rotate(0deg) scale(1); filter: blur(80px); }
}
@keyframes aurora-pulse {
  0%, 100% { opacity: 0.15; }
  50%       { opacity: 0.28; }
}

/* ─────────────────────────────────────────────────────────
    ANIMATIONS — Core
───────────────────────────────────────────────────────── */

@keyframes fadeDown {
  from { opacity: 0; transform: translateY(-30px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes glow-text {
  0%, 100% { text-shadow: 0 0 20px rgba(56,189,248,0.4), 0 0 40px rgba(56,189,248,0.2); }
  50%       { text-shadow: 0 0 40px rgba(167,139,250,0.6), 0 0 80px rgba(167,139,250,0.3); }
}
@keyframes glow-border-animate {
  0%, 100% { box-shadow: 0 0 8px rgba(56,189,248,0.3), inset 0 0 8px rgba(56,189,248,0.05); }
  50%       { box-shadow: 0 0 20px rgba(167,139,250,0.4), inset 0 0 15px rgba(167,139,250,0.08); }
}
@keyframes orbiting-ring {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}
@keyframes border-spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}
@keyframes drift {
  0%, 100% { transform: translate(0, 0); }
  25%       { transform: translate(30px, -20px); }
  50%       { transform: translate(-20px, 30px); }
  75%       { transform: translate(20px, 10px); }
}
@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}
@keyframes pulse-glow {
  0%, 100% { opacity: 1; box-shadow: 0 0 6px rgba(52,211,153,0.5); }
  50%       { opacity: 0.6; box-shadow: 0 0 14px rgba(52,211,153,0.8); }
}
@keyframes gradient-shift {
  0%   { background-position: 0% 50%; }
  50%  { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}
@keyframes bounce-in {
  0%   { transform: scale(0); opacity: 0; }
  60%  { transform: scale(1.1); }
  80%  { transform: scale(0.95); }
  100% { transform: scale(1); opacity: 1; }
}

/* ─────────────────────────────────────────────────────────
    AURORA / NEBULA BLOBS
───────────────────────────────────────────────────────── */
.aurora {
  position: fixed; inset: 0; z-index: 0; pointer-events: none; overflow: hidden;
}
.aurora-blob {
  position: absolute; border-radius: 50%; filter: blur(80px);
  animation: aurora-shift 20s ease-in-out infinite, aurora-pulse 8s ease-in-out infinite;
}
.aurora-blob:nth-child(1) {
  width: 600px; height: 600px; top: -10%; left: -15%;
  background: radial-gradient(circle, rgba(56,189,248,0.18) 0%, transparent 70%);
  animation-delay: 0s;
}
.aurora-blob:nth-child(2) {
  width: 500px; height: 500px; top: 30%; right: -10%;
  background: radial-gradient(circle, rgba(167,139,250,0.15) 0%, transparent 70%);
  animation-delay: -5s;
}
.aurora-blob:nth-child(3) {
  width: 450px; height: 450px; bottom: 10%; left: 20%;
  background: radial-gradient(circle, rgba(244,114,182,0.12) 0%, transparent 70%);
  animation-delay: -10s;
}
.aurora-blob:nth-child(4) {
  width: 400px; height: 400px; bottom: -5%; right: 15%;
  background: radial-gradient(circle, rgba(52,211,153,0.1) 0%, transparent 70%);
  animation-delay: -15s;
}

/* ─────────────────────────────────────────────────────────
    AMBIENT ORBS — Visible background layer
───────────────────────────────────────────────────────── */
.ambient-orb {
  position: fixed; border-radius: 50%; pointer-events: none; z-index: 0;
  filter: blur(60px); animation: orb-pulse 6s ease-in-out infinite;
}
.ambient-orb-1 {
  width: 500px; height: 500px; top: -150px; left: -100px;
  background: radial-gradient(circle, rgba(56,189,248,0.12) 0%, transparent 70%);
  animation: orb-float-1 25s ease-in-out infinite, orb-pulse 8s ease-in-out infinite;
}
.ambient-orb-2 {
  width: 400px; height: 400px; top: 40%; right: -80px;
  background: radial-gradient(circle, rgba(167,139,250,0.1) 0%, transparent 70%);
  animation: orb-float-2 30s ease-in-out infinite, orb-pulse 10s ease-in-out infinite;
  animation-delay: -8s;
}
.ambient-orb-3 {
  width: 350px; height: 350px; bottom: 5%; left: 10%;
  background: radial-gradient(circle, rgba(244,114,182,0.08) 0%, transparent 70%);
  animation: orb-float-3 22s ease-in-out infinite, orb-pulse 7s ease-in-out infinite;
  animation-delay: -4s;
}

/* ─────────────────────────────────────────────────────────
    PREMIUM GLASS MORPHISM
───────────────────────────────────────────────────────── */
.glass {
  background: rgba(8, 13, 24, 0.4);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.3),
    0 1px 0 rgba(255, 255, 255, 0.06) inset,
    0 -1px 0 rgba(0, 0, 0, 0.15) inset;
}
.glass-light {
  background: rgba(240, 244, 255, 0.5);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  border: 1px solid rgba(15, 23, 42, 0.1);
  box-shadow:
    0 8px 32px rgba(15, 23, 42, 0.08),
    0 1px 0 rgba(255, 255, 255, 0.9) inset;
}
.glass-elevated {
  background: rgba(8, 13, 24, 0.6);
  backdrop-filter: blur(32px) saturate(200%);
  -webkit-backdrop-filter: blur(32px) saturate(200%);
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow:
    0 16px 48px rgba(0, 0, 0, 0.4),
    0 0 60px rgba(56,189,248,0.05),
    0 1px 0 rgba(255, 255, 255, 0.08) inset;
}

/* ─────────────────────────────────────────────────────────
    PREMIUM CARD STYLES
───────────────────────────────────────────────────────── */
.card {
  background: rgba(8, 13, 24, 0.5);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 20px;
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.3),
    0 1px 0 rgba(255, 255, 255, 0.05) inset;
  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  position: relative;
  overflow: hidden;
}
.card::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  width: 100%; height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.04), transparent);
  transition: left 0.6s ease;
}
.card:hover::before {
  left: 100%;
}
.card:hover {
  transform: translateY(-6px) scale(1.01);
  border-color: rgba(56, 189, 248, 0.2);
  box-shadow:
    0 24px 64px rgba(0, 0, 0, 0.4),
    0 0 40px rgba(56, 189, 248, 0.08),
    0 1px 0 rgba(255, 255, 255, 0.08) inset;
}

/* Animated gradient border */
.card-gradient-border {
  position: relative;
}
.card-gradient-border::after {
  content: '';
  position: absolute;
  inset: -1px;
  border-radius: inherit;
  background: linear-gradient(135deg, rgba(56,189,248,0.4), rgba(167,139,250,0.4), rgba(244,114,182,0.4), rgba(56,189,248,0.4));
  background-size: 300% 300%;
  animation: gradient-shift 4s ease infinite;
  z-index: -1;
  opacity: 0;
  transition: opacity 0.4s ease;
}
.card-gradient-border:hover::after {
  opacity: 1;
}

/* ─────────────────────────────────────────────────────────
    PREMIUM BUTTON STYLES
───────────────────────────────────────────────────────── */
.btn-primary {
  display: inline-flex; align-items: center; gap: 0.5rem;
  padding: 0.85rem 2rem;
  background: linear-gradient(135deg, var(--c1), var(--c2));
  background-size: 200% 200%;
  color: #04060f; border: none; border-radius: 16px;
  font-weight: 800; font-size: 0.9rem; font-family: var(--font-body);
  cursor: pointer; text-decoration: none;
  box-shadow: 0 8px 32px rgba(56,189,248,0.3), 0 0 0 0 rgba(56,189,248,0);
  transition: all 0.35s cubic-bezier(0.34, 1.56, 0.64, 1);
  animation: gradient-shift 4s ease infinite;
}
.btn-primary:hover {
  transform: translateY(-4px) scale(1.03);
  box-shadow: 0 20px 60px rgba(56,189,248,0.4), 0 0 40px rgba(56,189,248,0.15);
}
.btn-primary:active {
  transform: translateY(-2px) scale(1.01);
}

.btn-secondary {
  display: inline-flex; align-items: center; gap: 0.5rem;
  padding: 0.8rem 1.9rem;
  background: rgba(255,255,255,0.06);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 14px;
  color: var(--text); font-weight: 600; font-size: 0.88rem;
  font-family: var(--font-body);
  cursor: pointer; text-decoration: none;
  transition: all 0.28s ease;
  box-shadow: 0 4px 16px rgba(0,0,0,0.2);
}
.btn-secondary:hover {
  background: rgba(255,255,255,0.1);
  border-color: rgba(56,189,248,0.3);
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(0,0,0,0.3), 0 0 20px rgba(56,189,248,0.08);
}

/* ─────────────────────────────────────────────────────────
    PREMIUM TYPOGRAPHY EFFECTS
───────────────────────────────────────────────────────── */
.grad-text {
  background: linear-gradient(135deg, var(--c1), var(--c2), var(--c3), var(--c1));
  background-size: 300% 300%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: gradient-shift 5s ease infinite;
}
.glow-text {
  animation: glow-text 3s ease-in-out infinite;
}
.text-shimmer {
  background: linear-gradient(90deg, var(--c1), var(--c2), var(--c3), var(--c1));
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: shimmer 3s linear infinite;
}

/* ─────────────────────────────────────────────────────────
    SECTION DIVIDERS
───────────────────────────────────────────────────────── */
.section-divider {
  position: relative;
  height: 80px;
  overflow: hidden;
}
.section-divider::before {
  content: '';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  width: 60%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(56,189,248,0.3), rgba(167,139,250,0.3), transparent);
}
.section-divider::after {
  content: '';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  width: 120px; height: 40px;
  background: var(--bg);
  border: 1px solid rgba(56,189,248,0.2);
  border-radius: 50%;
  z-index: 1;
}
.divider-dots {
  display: flex; gap: 6px; align-items: center; justify-content: center;
}
.divider-dots span {
  width: 4px; height: 4px; border-radius: 50%;
  background: var(--c1); opacity: 0.4;
}
.divider-dots span:nth-child(2) { background: var(--c2); opacity: 0.6; }
.divider-dots span:nth-child(3) { background: var(--c3); opacity: 0.4; }

/* ─────────────────────────────────────────────────────────
    DECORATIVE ELEMENTS
───────────────────────────────────────────────────────── */
.corner-accent {
  position: absolute;
  width: 40px; height: 40px;
}
.corner-accent.top-left {
  top: 0; left: 0;
  border-top: 2px solid rgba(56,189,248,0.4);
  border-left: 2px solid rgba(56,189,248,0.4);
  border-radius: 8px 0 0 0;
}
.corner-accent.top-right {
  top: 0; right: 0;
  border-top: 2px solid rgba(167,139,250,0.4);
  border-right: 2px solid rgba(167,139,250,0.4);
  border-radius: 0 8px 0 0;
}
.corner-accent.bottom-left {
  bottom: 0; left: 0;
  border-bottom: 2px solid rgba(244,114,182,0.4);
  border-left: 2px solid rgba(244,114,182,0.4);
  border-radius: 0 0 0 8px;
}
.corner-accent.bottom-right {
  bottom: 0; right: 0;
  border-bottom: 2px solid rgba(52,211,153,0.4);
  border-right: 2px solid rgba(52,211,153,0.4);
  border-radius: 0 0 8px 0;
}
